// ---------------------------------------------------------------------------
// Registry: normalised name → { icon component }
// ---------------------------------------------------------------------------
type IconEntry = { component: () => React.JSX.Element };

const registry: Record<string, IconEntry> = {
  // Core
  "next.js":                  { component: NextjsIcon },
  "nextjs":                   { component: NextjsIcon },
  "tailwind css":             { component: TailwindIcon },
  "tailwindcss":              { component: TailwindIcon },
  "typescript":               { component: TypeScriptIcon },
  "react":                    { component: ReactIcon },
  "react.js":                 { component: ReactIcon },
  "figma":                    { component: FigmaIcon },
  "vercel":                   { component: VercelIcon },
  "aws":                      { component: AwsIcon },
  "postman":                  { component: PostmanIcon },
  "node.js":                  { component: NodejsIcon },
  "nodejs":                   { component: NodejsIcon },
  "mongodb":                  { component: MongodbIcon },
  "git":                      { component: GitIcon },
  "redux":                    { component: ReduxIcon },
  "redux toolkit":            { component: ReduxIcon },
  "webpack":                  { component: WebpackIcon },
  "jest":                     { component: JestIcon },
  "vite":                     { component: ViteIcon },
  "mysql":                    { component: MysqlIcon },
  "context api":              { component: ContextApiIcon },
  "websockets":               { component: WebSocketIcon },
  "html5":                    { component: HTML5Icon },
  "css3":                     { component: CSS3Icon },
  "material ui":              { component: MaterialUIIcon },
  "express.js":               { component: ExpressJSIcon },
  "expressjs":                { component: ExpressJSIcon },
  "react testing library":    { component: ReactTestingLibraryIcon },
  "rtl":                      { component: ReactTestingLibraryIcon },
  "tdd":                      { component: TDDIcon },
  "sonarqube":                { component: SonarQubeIcon },
  "eslint":                   { component: ESLintIcon },
  "axios":                    { component: AxiosIcon },
  "framer motion":            { component: FramerMotionIcon },
  "netlify":                  { component: NetlifyIcon },
  "rest apis":                { component: RestApiIcon },
  "jwt authentication":       { component: JwtIcon },
  "enzyme":                   { component: EnzymeIcon },
  "code review":              { component: CodeReviewIcon },
};

function lookup(name: string): IconEntry | undefined {
  return registry[name.toLowerCase()];
}

// ---------------------------------------------------------------------------
// SkillPill — monochromatic tile, icon always visible, name slides in on hover
// ---------------------------------------------------------------------------
export function SkillPill({ name, iconOnly = false }: { name: string; iconOnly?: boolean }) {
  const entry = lookup(name);

  if (!entry) {
    return (
      <span className="inline-flex items-center rounded-md border border-zinc-200 bg-zinc-50 px-2.5 py-1 text-xs font-bold uppercase tracking-wider text-zinc-600 dark:border-zinc-800 dark:bg-zinc-900 dark:text-zinc-400">
        {name}
      </span>
    );
  }

  const IconComponent = entry.component;

  if (iconOnly) {
    return (
      <div
        className="inline-flex h-12 w-12 items-center justify-center rounded-lg border border-zinc-200 bg-white text-zinc-900 shadow-sm transition-all duration-300 hover:border-zinc-900 hover:scale-105 dark:border-zinc-800 dark:bg-zinc-950 dark:text-white dark:hover:border-white [&_svg]:size-7 grayscale hover:grayscale-0"
        aria-label={name}
        title={name}
      >
        <IconComponent />
      </div>
    );
  }

  return (
    <div className="group inline-flex items-center gap-0 rounded-lg border border-zinc-200 bg-white px-3 py-1.5 text-xs font-semibold text-zinc-600 shadow-sm transition-all duration-300 ease-out hover:border-zinc-900 hover:text-zinc-950 dark:border-zinc-800 dark:bg-[#111111] dark:text-zinc-400 dark:hover:border-zinc-500 dark:hover:text-white [&_svg]:size-4">
      <span className="size-4 shrink-0 grayscale group-hover:grayscale-0 transition-all duration-300">
        <IconComponent />
      </span>
      <span className="max-w-0 overflow-hidden opacity-0 whitespace-nowrap transition-all duration-500 ease-out group-hover:max-w-32 group-hover:opacity-100 group-hover:ml-2">
        {name}
      </span>
    </div>
  );
}

// ---------------------------------------------------------------------------
// TechChip — same hover-expand animation as SkillPill, slightly smaller
// ---------------------------------------------------------------------------
export function TechChip({ name }: { name: string }) {
  const entry = lookup(name);

  if (!entry) {
    return (
      <span className="inline-flex items-center rounded-md border border-zinc-200 bg-zinc-50 px-2 py-0.5 text-[10px] font-bold uppercase tracking-wider text-zinc-500 dark:border-zinc-800 dark:bg-zinc-900 dark:text-zinc-500">
        {name}
      </span>
    );
  }

  const IconComponent = entry.component;

  return (
    <div className="group inline-flex items-center gap-0 rounded-md border border-zinc-200 bg-white px-2 py-1 text-[10px] font-bold uppercase tracking-wider text-zinc-500 shadow-sm transition-all duration-300 ease-out hover:border-zinc-900 hover:text-zinc-900 dark:border-zinc-800 dark:bg-[#111111] dark:text-zinc-500 dark:hover:border-zinc-500 dark:hover:text-white [&_svg]:size-3">
      <span className="size-3 shrink-0 grayscale group-hover:grayscale-0 transition-all duration-300">
        <IconComponent />
      </span>
      <span className="max-w-0 overflow-hidden opacity-0 whitespace-nowrap transition-all duration-500 ease-out group-hover:max-w-28 group-hover:opacity-100 group-hover:ml-1.5">
        {name}
      </span>
    </div>
  );
}
